/**
 * auto-seed.ts
 * Called automatically when a product is created or updated in the admin.
 * Seeds ProductCityPage rows for all approved product × city combos.
 * Never overwrites manually edited content (isAutoGenerated = false).
 */

import prisma from '@/lib/prisma';
import {
  isApprovedForCityPages,
  TOP_CITIES_FOR_PRODUCT_PAGES,
  CITY_DELIVERY_ESTIMATES,
  getCityBySlug,
} from './city-data';

interface ProductInfo {
  slug: string;
  name: string;
  description: string;
  price: number;
  salePrice?: number | null;
  lightReq: string;
  waterReq?: string | null;
  careLevel: string;
}

