function generateCareTip(product: ProductInfo, citySlug: string): string {
  const override = CITY_CARE_OVERRIDES[product.slug]?.[citySlug];
  if (override) return override;

  const city = getCityBySlug(citySlug);
  const cityName = city?.cityName ?? citySlug;
  const lightMap: Record<string, string> = {
    LOW: 'low indirect light — perfect for indoor corners',
    MEDIUM: 'bright indirect light near a window',
    HIGH: 'direct or very bright indirect light',
  };
  const lightText = lightMap[product.lightReq] ?? 'indirect light';
  const waterText = product.waterReq
    ? `water ${product.waterReq.toLowerCase()}`
    : 'water when the top inch of soil feels dry';

  return `${product.name} grows well in ${cityName}'s climate. Place it in ${lightText} and ${waterText}. ${cityName}'s temperature range suits this plant for year-round indoor display.`;
}

function generateH1(productName: string, cityName: string): string {
  return `Buy ${productName} Online in ${cityName} — Fresh Delivery`;
}

function generateMetaTitle(productName: string, cityName: string, price: number): string {
  return `Buy ${productName} in ${cityName} — Rs ${price} Free Delivery | IndoorPlant.in`;
}

function generateMetaDesc(product: ProductInfo, cityName: string, deliveryEstimate: string): string {
  const price = product.salePrice ?? product.price;
  return `Get ${product.name} delivered fresh in ${cityName} in ${deliveryEstimate}. Starting at Rs ${price}. Expert-packed, damage-protected delivery. AI plant care advice included.`;
}

/**
 * Called from the admin product save action.
 * Idempotent — safe to call on every product update.
 */
export async function onProductSaved(product: ProductInfo): Promise<void> {
  if (!isApprovedForCityPages(product.slug)) return;

  const upsertOps = TOP_CITIES_FOR_PRODUCT_PAGES.map((citySlug) => {
    const city = getCityBySlug(citySlug);
    const cityName = city?.cityName ?? citySlug;
    const deliveryEstimate = CITY_DELIVERY_ESTIMATES[citySlug] ?? '3–5 business days';
    const price = product.salePrice ?? product.price;

    const defaults = {
      metaTitle:    generateMetaTitle(product.name, cityName, price),
      metaDesc:     generateMetaDesc(product, cityName, deliveryEstimate),
      h1:           generateH1(product.name, cityName),
      localCareTip: generateCareTip(product, citySlug),
      deliveryNote: `Delivered in ${deliveryEstimate} across ${cityName}`,
      isAutoGenerated: true,
      isActive: true,
      isIndexed: true,
    };

    return prisma.productCityPage.upsert({
      where: { productSlug_citySlug: { productSlug: product.slug, citySlug } },
      create: { productSlug: product.slug, citySlug, ...defaults },
      // Only update auto-generated records — never overwrite manually edited content
      update: {
        metaTitle:    { set: defaults.metaTitle },
        metaDesc:     { set: defaults.metaDesc },
        h1:           { set: defaults.h1 },
        localCareTip: { set: defaults.localCareTip },
        deliveryNote: { set: defaults.deliveryNote },
      },
    });
  });

  await Promise.all(upsertOps);

  // Revalidate all affected city pages so Next.js cache is cleared
  const { revalidatePath } = await import('next/cache');
  for (const citySlug of TOP_CITIES_FOR_PRODUCT_PAGES) {
    revalidatePath(`/shop/${product.slug}/${citySlug}`);
  }
}
